import java.util.*;

class Codechef {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        int t = sc.nextInt();

        while (t--> 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();

            int[][] v = new int[n][2];
            for (int i = 0; i < n; i++) {
                v[i][0] = sc.nextInt();
            }
            for (int i = 0; i < n; i++) {
                v[i][1] = sc.nextInt();
            }

            Arrays.sort(v, (a, b) -> {
                int sumA = a[0] + a[1];
                int sumB = b[0] + b[1];
                if (sumA == sumB) {
                    return Integer.compare(b[0], a[0]);
                }
                return Integer.compare(sumA, sumB);
            });

            int ans = 0, cur = 0;
            for (int i = 0; i < n; i++) {
                cur += v[i][0] + v[i][1];
                if (cur <= k) continue;

                ans = i;
                int mn1 = Integer.MAX_VALUE, mn2 = Integer.MAX_VALUE;

                for (int j = 0; j < n; j++) {
                    if (v[j][0] + v[j][1] <= v[i][0] + v[i][1]) {
                        mn1 = Math.min(mn1, cur - v[j][1]);
                    }
                }

                if (mn1 <= k) ans = i + 1;

                cur -= v[i][0] + v[i][1];

                for (int j = i; j < n; j++) {
                    mn2 = Math.min(mn2, cur + v[j][0]);
                }

                cur += v[i][0] + v[i][1];
                if (mn2 <= k) ans = i + 1;

                break;
            }

            if (cur <= k) ans = n;
            System.out.println(ans);
        }

        sc.close();
    }
}
